import { BrowserRouter, Route, Routes } from "react-router-dom";
import { SettingsContextProvider } from "./hooks/useSettings";
import { Book, Home } from "./pages";
import Layout from "./components/major/Layout";

function App() {
  return (
    <SettingsContextProvider>
      <BrowserRouter>
        <Layout>
          <Routes>
            <Route element={<Home />} path={"/"} />
            <Route element={<Book />} path={"/post/:id"} />
          </Routes>
        </Layout>
      </BrowserRouter>
    </SettingsContextProvider>
  );
}

export default App;
