import React from "react";

const LazyHome = React.lazy(() => import("./Home"));

export const Home = () => (
  <React.Suspense fallback={<div />}>
    <LazyHome />
  </React.Suspense>
);

const LazyBook = React.lazy(() => import("./Book"));

export const Book = () => (
  <React.Suspense fallback={<div />}>
    <LazyBook />
  </React.Suspense>
);
