import React from "react";
import { Link } from "react-router-dom";
import useSettings from "../../hooks/useSettings";

export default class Nav extends React.PureComponent {
  render() {
    return (
      <nav
        className="navbar navbar-dark shadow"
        style={{ backgroundColor: "#222" }}
      >
        <div className="container-fluid">
          <AppTitle />
          <Changers />
        </div>
      </nav>
    );
  }
}

const AppTitle = React.memo(() => (
  <Link
    to={"/"}
    className={"navbar-brand text-decoration-none text-uppercase fw-bold mb-0"}
  >
    Four Books
  </Link>
));

const Changers = () => {
  const { font, changeFont } = useSettings();

  return (
    <div>
      {/* <ThemeChanger onClick={changeTheme} /> */}
      <ZawgyiUnicodeChanger onClick={changeFont} font={font} />
    </div>
  );
};

