const ZawgyiUnicodeChanger = React.memo(({ onClick, font }) => (
  <button
    type="button"
    className={"btn btn-outline-success text-capitalize"}
    title={"zawgy unicode changer"}
    onClick={onClick}
  >
    {font}
  </button>
));
